import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useStore } from '@/store'
import { useRevision } from '@/hooks/useRevision'
import { signOut } from '@/hooks/useAuth'
import { TIPOS_TESIS, NORMAS, ACADEMIC_CHECKLIST, flattenFaseItems, flattenTipo } from '@/types'
import { relativeTime, cn } from '@/lib/utils'
import type { NormaType } from '@/types'
import type { LTMatch } from '@/hooks/useLanguageTool'
import ReferencesPanel from '@/components/references/ReferencesPanel'
import RevisionPanel   from '@/components/revision/RevisionPanel'
import GrammarPanel    from '@/components/revision/GrammarPanel'

const LOGO_SRC = 'data:image/png;base64,'

type PanelTab = 'structure' | 'refs' | 'revision' | 'grammar'

interface SidebarProps {
  grammarMatches?: LTMatch[]
  activeSectionForGrammar?: string
}

export default function Sidebar({ grammarMatches = [], activeSectionForGrammar }: SidebarProps) {
  const navigate = useNavigate()
  const {
    project, sections, norma, setNorma,
    revisionIssues, isSaving, lastSaved,
    activeSectionId, setActiveSection,
  } = useStore()
  const { runRevision } = useRevision()
  const [tab, setTab] = useState<PanelTab>('structure')

  const tipo           = project ? TIPOS_TESIS[project.tipo] : null
  const sectionByName  = new Map(sections.map(s => [s.name, s]))
  const totalWords     = sections.reduce((s, sec) => s + sec.word_count, 0)
  const flatLeaves      = tipo ? flattenTipo(tipo).filter(i => !i.isChapterHeader) : []
  const totalSections  = flatLeaves.length
  const filledNames     = new Set(sections.filter(s => s.word_count > 0).map(s => s.name))
  const filledSections = flatLeaves.filter(i => filledNames.has(i.name)).length
  const progress       = totalSections ? Math.round(filledSections / totalSections * 100) : 0
  const errorCount     = revisionIssues.filter(i => i.level === 'error').length
  const warnCount      = revisionIssues.filter(i => i.level === 'warning').length
  const grammarTotal   = grammarMatches.length

  // Academic-progress checklist: which key academic elements have content
  const checklist = project ? ACADEMIC_CHECKLIST[project.tipo] : []
  const checklistStatus = checklist.map(item => ({
    label: item.label,
    done: sections.some(s => s.word_count > 0 && item.match.some(m => s.name.includes(m))),
  }))

  const scrollToSection = (name: string) => {
    const sec = sectionByName.get(name)
    const id  = sec ? `section-${sec.id}` : `section-virtual-${name}`
    setActiveSection(sec?.id ?? `virtual-${name}`)
    const el = document.getElementById(id)
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' })
  }

  const handleFix = (match: LTMatch, replacement: string) => {
    window.dispatchEvent(new CustomEvent('apply-grammar-fix', {
      detail: { match, replacement, sectionId: activeSectionForGrammar }
    }))
  }

  const handleDismiss = (_match: LTMatch) => {}

  return (
    <aside className="w-64 min-w-64 flex flex-col bg-gradient-to-b from-brand-800 to-brand-950 border-r border-brand-700/50 overflow-hidden">

      <div className="flex items-center gap-2.5 px-3.5 py-3 border-b border-brand-700/40 flex-shrink-0">
        <div className="w-9 h-9 rounded-lg bg-white/10 border border-brand-600/30 flex items-center justify-center flex-shrink-0 overflow-hidden p-1">
          <img src={LOGO_SRC} alt="Graduate" className="w-full h-full object-contain" />
        </div>
        <div className="min-w-0">
          <div className="font-serif text-brand-100 text-base font-semibold leading-tight">
            Graduate{" "}
            <span className="text-xs bg-gold text-brand-950 rounded px-1 font-bold align-middle">PRO</span>
          </div>
          <div className="text-brand-500 text-xs">by RonnDu Corp.</div>
        </div>
      </div>

      <div className="px-3.5 py-2.5 border-b border-brand-700/40 flex-shrink-0 space-y-2">
        <button onClick={() => navigate("/")}
          className="flex items-center gap-1.5 text-brand-400 hover:text-brand-200 text-xs transition-colors w-full text-left">
          <i className="ti ti-chevron-left text-xs" />
          <span className="truncate">{project?.title ?? "Dashboard"}</span>
        </button>

        <div>
          <p className="text-brand-600 text-xs mb-1 uppercase tracking-wider">Norma</p>
          <div className="flex flex-wrap gap-1">
            {(["libre","apa","vancouver","ieee","chicago"] as NormaType[]).map(n => (
              <button key={n} onClick={() => setNorma(n)}
                className={cn(
                  "flex-1 min-w-[30%] text-xs py-1 rounded-md border transition-all",
                  norma === n
                    ? "bg-brand-500 text-white border-brand-500"
                    : "bg-brand-800/60 text-brand-400 border-brand-700 hover:border-brand-500"
                )}>
                {NORMAS[n].label}
              </button>
            ))}
          </div>
        </div>

        <div>
          <div className="flex justify-between text-xs text-brand-500 mb-1">
            <span>{filledSections}/{totalSections} secciones</span>
            <span>{totalWords.toLocaleString("es")} palabras</span>
          </div>
          <div className="h-1.5 bg-brand-800 rounded-full overflow-hidden">
            <div className="h-full bg-gradient-to-r from-brand-400 to-gold transition-all duration-500 rounded-full"
              style={{ width: `${progress}%` }} />
          </div>
        </div>

        {checklistStatus.length > 0 && (
          <div>
            <p className="text-brand-600 text-xs mb-1 uppercase tracking-wider">Avance académico</p>
            <div className="flex flex-wrap gap-x-2 gap-y-1">
              {checklistStatus.map(c => (
                <span key={c.label} className={cn(
                  "text-xs flex items-center gap-0.5",
                  c.done ? "text-green-400" : "text-brand-600"
                )}>
                  {c.done ? "✔" : "✘"} {c.label}
                </span>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="flex border-b border-brand-700/40 flex-shrink-0">
        {([
          { id: "structure", icon: "ti-layout-list",     badge: 0 },
          { id: "refs",      icon: "ti-books",            badge: 0 },
          { id: "grammar",   icon: "ti-text-spellcheck",  badge: grammarTotal },
          { id: "revision",  icon: "ti-shield-check",     badge: errorCount + warnCount },
        ] as const).map(t => (
          <button key={t.id}
            onClick={() => {
              if (t.id === "revision") { setTab("revision"); runRevision() }
              else setTab(t.id as PanelTab)
            }}
            className={cn(
              "flex-1 flex items-center justify-center py-2 text-sm border-b-2 transition-all relative",
              tab === t.id ? "text-gold border-gold" : "text-brand-500 border-transparent hover:text-brand-300"
            )}>
            <i className={`ti ${t.icon}`} />
            {t.badge > 0 && (
              <span className="absolute top-0.5 right-0.5 bg-red-500 text-white rounded-full w-3.5 h-3.5 flex items-center justify-center" style={{fontSize:"8px"}}>
                {t.badge > 9 ? "9+" : t.badge}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="flex-1 overflow-y-auto">
        {tab === "structure" && tipo && (
          <div className="py-1">
            {tipo.fases.map(fase => (
              <div key={fase.fase}>
                <div className="px-3.5 pt-3 pb-1">
                  <p className="text-brand-600 text-xs font-medium uppercase tracking-wider">
                    {fase.isRoman ? "(i,ii) " : "(1,2) "}{fase.fase}
                  </p>
                </div>
                {flattenFaseItems(fase).map(item => {
                  const { name, group, isChapterHeader } = item
                  const sec      = sectionByName.get(name)
                  const isActive = sec ? sec.id === activeSectionId : (`virtual-${name}` === activeSectionId)
                  const hasCont  = sec ? sec.word_count > 0 : false
                  return (
                    <button key={name} onClick={() => scrollToSection(name)}
                      className={cn(
                        "w-full flex items-start gap-2 py-1.5 text-left text-xs transition-all border-l-2",
                        group ? "pl-6 pr-3.5" : "px-3.5",
                        isChapterHeader && "font-medium",
                        isActive
                          ? "bg-brand-500/20 border-gold text-white"
                          : "border-transparent text-brand-400 hover:bg-brand-800/40 hover:text-brand-200"
                      )}>
                      <span className={cn(
                        "rounded-full mt-1 flex-shrink-0",
                        group ? "w-1 h-1" : "w-1.5 h-1.5",
                        isActive ? "bg-gold" : hasCont ? "bg-brand-400" : "bg-brand-700"
                      )} />
                      <span className="leading-tight">{group ? name.split(' · ')[1] : name}</span>
                      {hasCont && (
                        <span className="ml-auto text-brand-600 text-xs flex-shrink-0">{sec!.word_count}</span>
                      )}
                    </button>
                  )
                })}
              </div>
            ))}
          </div>
        )}
        {tab === "refs"     && <ReferencesPanel />}
        {tab === "revision" && <RevisionPanel />}
        {tab === "grammar"  && (
          <GrammarPanel
            matches={grammarMatches}
            checking={false}
            onFix={handleFix}
            onDismiss={handleDismiss}
          />
        )}
      </div>

      <div className="px-3.5 py-2 border-t border-brand-700/40 flex items-center justify-between flex-shrink-0">
        <div className="flex items-center gap-1.5">
          <span className={cn("w-1.5 h-1.5 rounded-full", isSaving ? "bg-gold animate-pulse" : "bg-green-400")} />
          <span className="text-brand-600 text-xs">
            {isSaving ? "Guardando..." : lastSaved ? relativeTime(lastSaved) : "Listo"}
          </span>
        </div>
        <button onClick={signOut} className="text-brand-600 hover:text-brand-400 text-xs transition-colors">
          <i className="ti ti-logout text-sm" />
        </button>
      </div>
    </aside>
  )
}
